class Solution:
    def maxConsecutive(self, bottom, top, special):
        marks = sorted(set(special))
        boundaries = [bottom - 1] + marks + [top + 1]
        best = 0
        for i in range(1, len(boundaries)):
            gap = boundaries[i] - boundaries[i - 1] - 1
            if gap > best:
                best = gap
        return best

