class Solution:
    def maxConsecutive(self, bottom, top, special):
        special = sorted(special)
        best = max(special[0] - bottom, top - special[-1])
        for i in range(1, len(special)):
            best = max(best, special[i] - special[i - 1] - 1)
        return best

